{\Large\bfseries All 3 Function Types -- Quick Reference}


\end{infobox}

example.javascript:
// 1. Function Declaration
function add1(a, b) {
  return a + b;
}

// 2. Function Expression
const add2 = function(a, b) {
  return a + b;
};

// 3. Arrow Function
const add3 = (a, b) => a + b;

// 
add1(3, 5); // 8
add2(3, 5); // 8
add3(3, 5); // 8

const a = x => x + 1;
const b = x => { x + 1 };
const c = x => { return x + 1; };

console.log(a(5));
console.log(b(5));
console.log(c(5));

